import 'dart:typed_data';

import 'package:test/test.dart';
import 'package:wasd/wasd.dart';

void main() {
  group('WasmComponent.decode', () {
    test('requires componentModel feature', () {
      final componentBytes = Uint8List.fromList(<int>[
        0x00,
        0x61,
        0x73,
        0x6d,
        0x0d,
        0x00,
        0x01,
        0x00,
      ]);

      expect(
        () => WasmComponent.decode(componentBytes),
        throwsA(isA<UnsupportedError>()),
      );
    });

    test('decodes a minimal component and exposes sections', () {
      // Generated by wasm-tools component encoder from `(module)`.
      final componentBytes = Uint8List.fromList(<int>[
        0x00,
        0x61,
        0x73,
        0x6d,
        0x0d,
        0x00,
        0x01,
        0x00,
        0x01,
        0x08,
        0x00,
        0x61,
        0x73,
        0x6d,
        0x01,
        0x00,
        0x00,
        0x00,
        0x02,
        0x04,
        0x01,
        0x00,
        0x00,
        0x00,
      ]);

      final component = WasmComponent.decode(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );

      expect(component.sections, hasLength(2));
      expect(component.coreModules, hasLength(1));
      expect(component.coreInstances, hasLength(1));
      expect(component.coreInstances.single.moduleIndex, 0);
      expect(
        component.coreModules.single,
        orderedEquals(const <int>[
          0x00,
          0x61,
          0x73,
          0x6d,
          0x01,
          0x00,
          0x00,
          0x00,
        ]),
      );
      expect(component.sections.first.id, 0x01);
      expect(component.sections.first.payload, hasLength(8));
      expect(component.sections[1].id, 0x02);
      expect(component.sections[1].payload, hasLength(4));
    });

    test('decodes core-instance instantiate args', () {
      final componentBytes = Uint8List.fromList(<int>[
        0x00,
        0x61,
        0x73,
        0x6d,
        0x0d,
        0x00,
        0x01,
        0x00,
        // section 1: one core module payload
        0x01,
        0x08,
        0x00,
        0x61,
        0x73,
        0x6d,
        0x01,
        0x00,
        0x00,
        0x00,
        // section 2: one core instance with arg_count=1
        0x02,
        0x05,
        0x01,
        0x00,
        0x00,
        0x01,
        0x00,
      ]);

      final component = WasmComponent.decode(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );

      expect(component.coreInstances, hasLength(1));
      expect(component.coreInstances.single.moduleIndex, 0);
      expect(
        component.coreInstances.single.argumentInstanceIndices,
        orderedEquals(const <int>[0]),
      );
    });

    test('decodes core export aliases from section 0x03', () {
      final componentBytes = Uint8List.fromList(<int>[
        0x00,
        0x61,
        0x73,
        0x6d,
        0x0d,
        0x00,
        0x01,
        0x00,
        // section 1: one core module payload
        0x01,
        0x08,
        0x00,
        0x61,
        0x73,
        0x6d,
        0x01,
        0x00,
        0x00,
        0x00,
        // section 2: one core instance declaration
        0x02,
        0x04,
        0x01,
        0x00,
        0x00,
        0x00,
        // section 3: one alias (instance0.foo -> apiFoo)
        0x03,
        0x0d,
        0x01,
        0x00,
        0x03,
        0x66,
        0x6f,
        0x6f,
        0x06,
        0x61,
        0x70,
        0x69,
        0x46,
        0x6f,
        0x6f,
      ]);

      final component = WasmComponent.decode(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );

      expect(component.coreExportAliases, hasLength(1));
      expect(component.coreExportAliases.single.instanceIndex, 0);
      expect(component.coreExportAliases.single.coreExportName, 'foo');
      expect(component.coreExportAliases.single.componentExportName, 'apiFoo');
    });

    test('rejects duplicate component export aliases in section 0x03', () {
      final componentBytes = Uint8List.fromList(<int>[
        0x00,
        0x61,
        0x73,
        0x6d,
        0x0d,
        0x00,
        0x01,
        0x00,
