        0x01,
        0x08,
        0x00,
        0x61,
        0x73,
        0x6d,
        0x01,
        0x00,
        0x00,
        0x00,
        // section 2: one core instance declaration
        0x02,
        0x04,
        0x01,
        0x00,
        0x00,
        0x00,
        // section 3: two aliases with same component export name `dup`
        0x03,
        0x19,
        0x02,
        0x00,
        0x03,
        0x66,
        0x6f,
        0x6f,
        0x03,
        0x64,
        0x75,
        0x70,
        0x00,
        0x03,
        0x62,
        0x61,
        0x72,
        0x03,
