    test('decodes type bindings from section 0x07', () {
      final importSection = <int>[
        ..._u32Leb(1),
        ..._name('incFn'),
        ..._name('host'),
        ..._name('inc'),
        0x00,
      ];
      final instanceSection = <int>[
        ..._u32Leb(1),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final exportAliasSection = <int>[
        ..._u32Leb(1),
        ..._u32Leb(0),
        ..._name('one'),
        ..._name('apiOne'),
      ];
      final typeSection = <int>[
        ..._u32Leb(1),
        ..._name('fn_t'),
        0x01,
        ..._u32Leb(1),
        0x7f,
        ..._u32Leb(1),
        0x7f,
      ];
      final typeBindingSection = <int>[
        ..._u32Leb(2),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(0),
        0x01,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x02, instanceSection),
        ..._section(0x03, exportAliasSection),
        ..._section(0x04, importSection),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      final component = WasmComponent.decode(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );

      expect(component.typeBindings, hasLength(2));
      expect(
        component.typeBindings[0].targetKind,
        WasmComponentTypeBindingTargetKind.importRequirement,
      );
      expect(component.typeBindings[0].targetIndex, 0);
      expect(component.typeBindings[0].typeDeclarationIndex, 0);
      expect(
        component.typeBindings[1].targetKind,
        WasmComponentTypeBindingTargetKind.coreExportAlias,
      );
      expect(component.typeBindings[1].targetIndex, 0);
      expect(component.typeBindings[1].typeDeclarationIndex, 0);
    });

    test('decodes unknown type-binding target kinds as opaque entries', () {
      final typeSection = <int>[
        ..._u32Leb(1),
        ..._name('fn_t'),
        0x01,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final typeBindingSection = <int>[
        ..._u32Leb(1),
        0x40,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      final component = WasmComponent.decode(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );
      expect(component.typeBindings, hasLength(1));
      expect(
        component.typeBindings.single.targetKind,
        WasmComponentTypeBindingTargetKind.opaque,
      );
      expect(component.typeBindings.single.rawTargetKind, 0x40);

      final bestEffort = WasmComponent.decodeBestEffort(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );
      expect(
        bestEffort.sections.where((section) => section.id == 0x07),
        hasLength(1),
      );
      expect(bestEffort.typeBindings, hasLength(1));
      expect(
        bestEffort.typeBindings.single.targetKind,
        WasmComponentTypeBindingTargetKind.opaque,
      );
      expect(bestEffort.typeDeclarations, hasLength(1));
    });

    test(
      'retains opaque type-binding entries when section has trailing bytes',
      () {
        final typeSection = <int>[
          ..._u32Leb(1),
          ..._name('fn_t'),
          0x01,
          ..._u32Leb(0),
          ..._u32Leb(0),
        ];
        final typeBindingSection = <int>[
          ..._u32Leb(1),
          0x40,
          ..._u32Leb(0),
          ..._u32Leb(0),
          0xff, // unknown trailing byte kept for forward-compat paths
        ];
        final componentBytes = Uint8List.fromList(<int>[
          ..._componentHeaderWithOneCoreModule(),
          ..._section(0x06, typeSection),
          ..._section(0x07, typeBindingSection),
        ]);

        final component = WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        );
        expect(component.typeBindings, hasLength(1));
        expect(
          component.typeBindings.single.targetKind,
          WasmComponentTypeBindingTargetKind.opaque,
        );
      },
    );

    test(
      'decodeBestEffort skips malformed structured import sections with trailing bytes',
      () {
        final malformedImportSection = <int>[
          ..._u32Leb(0),
          0x00, // trailing byte
        ];
        final componentBytes = Uint8List.fromList(<int>[
          ..._componentHeaderWithOneCoreModule(),
          ..._section(0x04, malformedImportSection),
        ]);

        expect(
          () => WasmComponent.decode(
            componentBytes,
            features: const WasmFeatureSet(componentModel: true),
          ),
          throwsFormatException,
        );

        final bestEffort = WasmComponent.decodeBestEffort(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        );
        expect(
          bestEffort.sections.where((section) => section.id == 0x04),
          hasLength(1),
        );
        expect(bestEffort.importRequirements, isEmpty);
      },
    );

