    test('accepts memory import type bindings at decode time', () {
      final importSection = <int>[
        ..._u32Leb(1),
        ..._name('mem'),
        ..._name('env'),
        ..._name('memory'),
        0x01,
      ];
      final typeSection = <int>[
        ..._u32Leb(1),
        ..._name('mem_t'),
        0x03, // memory
        0x01, // has max
        ..._u32Leb(1), // min pages
        ..._u32Leb(2), // max pages
      ];
      final typeBindingSection = <int>[
        ..._u32Leb(1),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x04, importSection),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      final component = WasmComponent.decode(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );
      expect(component.typeBindings, hasLength(1));
      expect(
        component.typeBindings.single.targetKind,
        WasmComponentTypeBindingTargetKind.importRequirement,
      );
      expect(component.typeBindings.single.targetIndex, 0);
      expect(component.typeBindings.single.typeDeclarationIndex, 0);
      expect(
        component.typeDeclarations.single.kind,
        WasmComponentTypeKind.memory,
      );
      expect(component.typeDeclarations.single.memoryType?.minPages, 1);
      expect(component.typeDeclarations.single.memoryType?.maxPages, 2);
    });

    test('accepts table/tag import type bindings at decode time', () {
      final importSection = <int>[
        ..._u32Leb(2),
        ..._name('tab'),
        ..._name('env'),
        ..._name('table'),
        0x02,
        ..._name('errTag'),
        ..._name('env'),
        ..._name('tag'),
        0x04,
      ];
      final typeSection = <int>[
        ..._u32Leb(2),
        ..._name('tab_t'),
        0x04, // table
        0x70, // funcref
        0x01, // has max
        ..._u32Leb(1), // min
        ..._u32Leb(2), // max
        ..._name('tag_t'),
        0x05, // tag
        ..._u32Leb(1), // param count
        0x7f, // i32
      ];
      final typeBindingSection = <int>[
        ..._u32Leb(2),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(0),
        0x00,
        ..._u32Leb(1),
        ..._u32Leb(1),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x04, importSection),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      final component = WasmComponent.decode(
        componentBytes,
        features: const WasmFeatureSet(componentModel: true),
      );
      expect(component.typeBindings, hasLength(2));
      expect(component.typeBindings[0].targetIndex, 0);
      expect(component.typeBindings[1].targetIndex, 1);
      expect(component.typeDeclarations[0].kind, WasmComponentTypeKind.table);
      expect(component.typeDeclarations[1].kind, WasmComponentTypeKind.tag);
      expect(
        component.typeDeclarations[1].tagParameterTypeCodes,
        orderedEquals(const <int>[0x7f]),
      );
    });

    test('rejects memory import type binding to non-memory declaration', () {
      final importSection = <int>[
        ..._u32Leb(1),
        ..._name('mem'),
        ..._name('env'),
        ..._name('memory'),
        0x01,
      ];
      final typeSection = <int>[..._u32Leb(1), ..._name('i32_t'), 0x00, 0x7f];
      final typeBindingSection = <int>[
        ..._u32Leb(1),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x04, importSection),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      expect(
        () => WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        ),
        throwsFormatException,
      );
    });

    test('rejects table import type binding to non-table declaration', () {
      final importSection = <int>[
        ..._u32Leb(1),
        ..._name('tab'),
        ..._name('env'),
        ..._name('table'),
        0x02,
      ];
      final typeSection = <int>[..._u32Leb(1), ..._name('i32_t'), 0x00, 0x7f];
      final typeBindingSection = <int>[
        ..._u32Leb(1),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x04, importSection),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      expect(
        () => WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        ),
        throwsFormatException,
      );
    });

    test('rejects tag import type binding to non-tag declaration', () {
      final importSection = <int>[
        ..._u32Leb(1),
        ..._name('errTag'),
        ..._name('env'),
        ..._name('tag'),
        0x04,
      ];
      final typeSection = <int>[..._u32Leb(1), ..._name('i32_t'), 0x00, 0x7f];
      final typeBindingSection = <int>[
        ..._u32Leb(1),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(0),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x04, importSection),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      expect(
        () => WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        ),
        throwsFormatException,
      );
    });

    test('rejects malformed component memory type declaration limits', () {
      final typeSection = <int>[
        ..._u32Leb(1),
        ..._name('mem_t'),
        0x03, // memory
        0x01, // has max
        ..._u32Leb(3), // min
        ..._u32Leb(2), // max
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x06, typeSection),
      ]);

      expect(
        () => WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        ),
        throwsFormatException,
      );
    });

    test(
      'rejects malformed shared component memory type declaration without max',
      () {
        final typeSection = <int>[
          ..._u32Leb(1),
          ..._name('mem_t'),
          0x03, // memory
          0x02, // shared without has-max
          ..._u32Leb(1), // min
        ];
        final componentBytes = Uint8List.fromList(<int>[
          ..._componentHeaderWithOneCoreModule(),
          ..._section(0x06, typeSection),
        ]);

        expect(
          () => WasmComponent.decode(
            componentBytes,
            features: const WasmFeatureSet(componentModel: true),
          ),
          throwsFormatException,
        );
      },
    );

    test('rejects malformed component table type declaration limits', () {
      final typeSection = <int>[
        ..._u32Leb(1),
        ..._name('tab_t'),
        0x04, // table
        0x70, // funcref
        0x01, // has max
        ..._u32Leb(4), // min
        ..._u32Leb(3), // max
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x06, typeSection),
      ]);

      expect(
        () => WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        ),
        throwsFormatException,
      );
    });

    test(
      'accepts core export alias type binding to non-function declaration at decode time',
      () {
        final instanceSection = <int>[
          ..._u32Leb(1),
          0x00,
          ..._u32Leb(0),
          ..._u32Leb(0),
        ];
        final exportAliasSection = <int>[
          ..._u32Leb(1),
          ..._u32Leb(0),
          ..._name('one'),
          ..._name('apiOne'),
        ];
        final typeSection = <int>[..._u32Leb(1), ..._name('i32_t'), 0x00, 0x7f];
        final typeBindingSection = <int>[
          ..._u32Leb(1),
          0x01,
          ..._u32Leb(0),
          ..._u32Leb(0),
        ];
        final componentBytes = Uint8List.fromList(<int>[
          ..._componentHeaderWithOneCoreModule(),
          ..._section(0x02, instanceSection),
          ..._section(0x03, exportAliasSection),
          ..._section(0x06, typeSection),
          ..._section(0x07, typeBindingSection),
        ]);

        final component = WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        );
        expect(component.typeBindings, hasLength(1));
        expect(
          component.typeDeclarations.single.kind,
          WasmComponentTypeKind.value,
        );
      },
    );

    test('rejects type bindings with out-of-range indexes', () {
      final typeSection = <int>[..._u32Leb(1), ..._name('i32_t'), 0x00, 0x7f];
      final typeBindingSection = <int>[
        ..._u32Leb(1),
        0x00,
        ..._u32Leb(0),
        ..._u32Leb(1),
      ];
      final componentBytes = Uint8List.fromList(<int>[
        ..._componentHeaderWithOneCoreModule(),
        ..._section(0x04, <int>[
          ..._u32Leb(1),
          ..._name('x'),
          ..._name('m'),
          ..._name('n'),
          0x00,
        ]),
        ..._section(0x06, typeSection),
        ..._section(0x07, typeBindingSection),
      ]);

      expect(
        () => WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        ),
        throwsFormatException,
      );
    });

    test('rejects unsupported component version', () {
      final componentBytes = Uint8List.fromList(<int>[
        0x00,
        0x61,
        0x73,
        0x6d,
        0x01,
        0x00,
        0x00,
        0x00,
      ]);

      expect(
        () => WasmComponent.decode(
          componentBytes,
          features: const WasmFeatureSet(componentModel: true),
        ),
        throwsFormatException,
      );
    });
  });
}

List<int> _componentHeaderWithOneCoreModule() {
  return <int>[
    0x00,
    0x61,
    0x73,
    0x6d,
    0x0d,
    0x00,
    0x01,
    0x00,
    0x01,
    0x08,
    0x00,
    0x61,
    0x73,
    0x6d,
    0x01,
    0x00,
    0x00,
    0x00,
  ];
}

List<int> _section(int id, List<int> payload) => <int>[
  id,
  ..._u32Leb(payload.length),
  ...payload,
];

List<int> _name(String value) => <int>[
  ..._u32Leb(value.length),
  ...value.codeUnits,
];

List<int> _u32Leb(int value) {
  if (value < 0) {
    throw ArgumentError.value(value, 'value', 'must be >= 0');
  }
  final out = <int>[];
  var remaining = value;
  do {
    var byte = remaining & 0x7f;
    remaining >>= 7;
    if (remaining != 0) {
      byte |= 0x80;
    }
    out.add(byte);
  } while (remaining != 0);
  return out;
}
